evaluators.evaluation_logic:
const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const sessions = JSON.parse(localStorage.getItem('event_sessions') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');
const regChildren = JSON.parse(localStorage.getItem('registration_children') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
const baselineDate = baselineDateStr ? new Date(baselineDateStr) : null;

function findEvent(id) { return events.find(e => e.id === id); }
function findSession(id) { return sessions.find(s => s.id === id); }

// Registrations likely created during this evaluation session (after baselineDate if available)
const userRegs = regs.filter(r => {
  if (!baselineDate) return true;
  const d = r.registration_date ? new Date(r.registration_date) : null;
  return d && d >= baselineDate;
});

// Affordable July 2025 summer Bible camps with a morning session
const july2025Start = new Date('2025-07-01T00:00:00Z');
const july2025End = new Date('2025-07-31T23:59:59Z');

const qualifyingEvents = events.filter(e => {
  if (e.event_type !== 'summer_bible_camp') return false;
  const start = e.start_date ? new Date(e.start_date) : null;
  if (!start || start < july2025Start || start > july2025End) return false;
  if (typeof e.base_price_per_child !== 'number' || e.base_price_per_child > 200) return false;
  const evSessions = sessions.filter(s => s.event_id === e.id);
  return evSessions.some(s => s.session_type === 'morning');
});

// Cheapest qualifying July 2025 morning camp
let cheapestEvent = null;
if (qualifyingEvents.length) {
  cheapestEvent = qualifyingEvents.slice().sort((a, b) => (a.base_price_per_child || 0) - (b.base_price_per_child || 0))[0];
}

// User registrations that meet all task criteria
const qualifyingRegs = userRegs.filter(r => {
  const ev = findEvent(r.event_id);
  if (!ev) return false;
  if (!qualifyingEvents.some(e => e.id === ev.id)) return false;
  if (r.payment_method !== 'pay_at_check_in') return false;
  const children = regChildren.filter(c => c.event_registration_id === r.id);
  if (children.length < 2) return false;
  const allChildrenOk = children.every(c => {
    if (typeof c.age !== 'number' || c.age < 7 || c.age > 10) return false;
    const sess = findSession(c.event_session_id);
    if (!sess || sess.session_type !== 'morning') return false;
    return sess.event_id === ev.id;
  });
  return allChildrenOk;
});

// CP1 (0.4): At least one registration with 2+ children ages 7–10 for an affordable July 2025 summer Bible camp morning session paid at check-in
checkpoints.push({ passed: qualifyingRegs.length >= 1, weight: 0.4 });

// CP2 (0.3): At least one such registration has exactly two children registered
const regWithExactlyTwoKids = qualifyingRegs.find(r => regChildren.filter(c => c.event_registration_id === r.id).length === 2);
checkpoints.push({ passed: !!regWithExactlyTwoKids, weight: 0.3 });

// CP3 (0.3): At least one such registration is for the cheapest qualifying July 2025 morning camp
const regForCheapest = cheapestEvent && qualifyingRegs.some(r => r.event_id === cheapestEvent.id);
checkpoints.push({ passed: !!regForCheapest, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const funds = JSON.parse(localStorage.getItem('donation_funds') || '[]');
const donations = JSON.parse(localStorage.getItem('donations') || '[]');

function hasAllKeywords(str, keywords) {
  if (!str) return false;
  const lower = str.toLowerCase();
  return keywords.every(kw => lower.includes(kw.toLowerCase()));
}

// Fund that provides illustrated Bibles, story cards, and activity guides
const targetFund = funds.find(f => hasAllKeywords(f.description || '', ['illustrated Bibles', 'story cards', 'activity guides']));

// Second-lowest suggested amount for that fund
let secondLowest = null;
if (targetFund && Array.isArray(targetFund.default_amount_suggestions) && targetFund.default_amount_suggestions.length >= 2) {
  const sorted = targetFund.default_amount_suggestions.slice().sort((a, b) => a - b);
  secondLowest = sorted[1];
}

// Monthly donations to this fund with offline payment and dedication in honor of Mary
const candidateDonations = donations.filter(d => {
  if (d.donation_type !== 'monthly') return false;
  if (!targetFund || d.fund_id !== targetFund.id) return false;
  if (d.payment_method === 'online_card') return false; // must be offline (bill_me_by_mail or pay_later_instructions)
  if (!d.dedication_enabled) return false;
  if (d.dedication_type !== 'in_honor_of') return false;
  const name = (d.honoree_name || '').toLowerCase();
  if (!name.includes('mary')) return false;
  return true;
});

// CP1 (0.5): Monthly donation to the correct children’s Bible story fund with offline payment and an in-honor-of dedication mentioning Mary
checkpoints.push({ passed: candidateDonations.length >= 1, weight: 0.5 });

// CP2 (0.3): At least one such donation uses the second-lowest suggested amount for that fund
const hasCorrectAmount = secondLowest != null && candidateDonations.some(d => d.amount === secondLowest);
checkpoints.push({ passed: hasCorrectAmount, weight: 0.3 });

// CP3 (0.2): At least one such donation opts to cover processing fees
const coversFees = candidateDonations.some(d => d.cover_processing_fee === true);
checkpoints.push({ passed: coversFees, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpts = [];

const crafts = JSON.parse(localStorage.getItem('craft_activities') || '[]');
const savedResources = JSON.parse(localStorage.getItem('saved_resources') || '[]');
const collections = JSON.parse(localStorage.getItem('resource_collections') || '[]');
const collectionItems = JSON.parse(localStorage.getItem('collection_items') || '[]');

// Use a shorter alias for checkpoints variable name
const checkpoints = checkpts;

// Collection named exactly "Easter 6–8 Crafts"
const targetCollection = collections.find(c => c.name === 'Easter 6–8 Crafts');

// First three qualifying Easter crafts for ages 6–8 with duration <= 30, sorted by most_downloaded
const qualifyingCrafts = crafts.filter(c => {
  if (c.status !== 'active') return false;
  if (c.seasonal_topic !== 'easter') return false;
  const min = typeof c.min_age === 'number' ? c.min_age : 0;
  const max = typeof c.max_age === 'number' ? c.max_age : Infinity;
  if (min > 8 || max < 6) return false; // overlap with ages 6–8
  if ((c.estimated_duration_minutes || 0) > 30) return false;
  return true;
}).sort((a, b) => (b.download_count || 0) - (a.download_count || 0));

const topThree = qualifyingCrafts.slice(0, 3);
const topThreeIds = topThree.map(c => c.id);

// Craft IDs actually in the target collection
let craftIdsInCollection = [];
if (targetCollection) {
  const itemsForCollection = collectionItems.filter(ci => ci.collection_id === targetCollection.id);
  craftIdsInCollection = itemsForCollection.map(ci => {
    const saved = savedResources.find(sr => sr.id === ci.saved_resource_id);
    return saved && saved.resource_type === 'craft_activity' ? saved.resource_id : null;
  }).filter(id => !!id);
}

const qualifyingCount = craftIdsInCollection.filter(id => topThreeIds.includes(id)).length;

// CP1 (0.3): Collection with the correct name contains at least one of the top three qualifying Easter 6–8 crafts
checkpoints.push({ passed: qualifyingCount >= 1, weight: 0.3 });

// CP2 (0.3): Collection contains at least two of the top three qualifying crafts
checkpoints.push({ passed: qualifyingCount >= 2, weight: 0.3 });

// CP3 (0.4): Collection contains all three of the top qualifying Easter crafts
checkpoints.push({ passed: qualifyingCount >= 3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

const cartId = currentCartId;
const itemsForCart = cartItems.filter(ci => ci.cart_id === cartId);

function findBestCurriculum(minAgeTarget, maxAgeTarget) {
  const candidates = products.filter(p => {
    if (p.category_id !== 'curriculum_sets') return false;
    if (!Array.isArray(p.tags) || !p.tags.includes('fruit_of_the_spirit')) return false;
    if (typeof p.price !== 'number' || p.price > 25) return false;
    const min = typeof p.min_age === 'number' ? p.min_age : 0;
    const max = typeof p.max_age === 'number' ? p.max_age : Infinity;
    if (min > maxAgeTarget || max < minAgeTarget) return false; // age overlap
    return true;
  });
  if (!candidates.length) return null;
  return candidates.slice().sort((a, b) => (b.rating_average || 0) - (a.rating_average || 0))[0];
}

const bestPreschool = findBestCurriculum(3, 5);
const bestPreteen = findBestCurriculum(9, 11);

// CP1 (0.5): Cart contains the highest-rated under-$25 Fruit of the Spirit curriculum set for preschool (ages 3–5)
const hasPreschool = !!(bestPreschool && itemsForCart.some(ci => ci.product_id === bestPreschool.id && ci.quantity > 0));
checkpoints.push({ passed: hasPreschool, weight: 0.5 });

// CP2 (0.5): Cart contains the highest-rated under-$25 Fruit of the Spirit curriculum set for preteens (ages 9–11)
const hasPreteen = !!(bestPreteen && itemsForCart.some(ci => ci.product_id === bestPreteen.id && ci.quantity > 0));
checkpoints.push({ passed: hasPreteen, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const opportunities = JSON.parse(localStorage.getItem('volunteer_opportunities') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('volunteer_time_slots') || '[]');
const applications = JSON.parse(localStorage.getItem('volunteer_applications') || '[]');
const campuses = JSON.parse(localStorage.getItem('campus_sites') || '[]');

function findOpportunity(id) { return opportunities.find(o => o.id === id); }
function findTimeSlot(id) { return timeSlots.find(ts => ts.id === id); }
function findCampus(id) { return campuses.find(c => c.id === id); }

// Applications for open, in-person, children-focused roles at a campus in ZIP 30309 within 10 miles
const appsWithQualifyingOpportunity = applications.filter(app => {
  const opp = findOpportunity(app.volunteer_opportunity_id);
  if (!opp) return false;
  if (opp.status !== 'open') return false;
  if (opp.serve_type !== 'in_person') return false;
  if (opp.role_focus !== 'work_directly_with_children') return false;
  const campus = opp.campus_site_id ? findCampus(opp.campus_site_id) : null;
  if (!campus || String(campus.postal_code) !== '30309') return false;
  if (typeof opp.distance_miles_from_search === 'number' && opp.distance_miles_from_search > 10) return false;
  return true;
});

// Among those, applications that select a Sunday morning time slot
const appsWithSundayMorningSlot = appsWithQualifyingOpportunity.filter(app => {
  if (!app.selected_time_slot_id) return false;
  const slot = findTimeSlot(app.selected_time_slot_id);
  if (!slot) return false;
  if (slot.day_of_week !== 'sunday') return false;
  if (slot.time_block !== 'morning_8_12') return false;
  return slot.volunteer_opportunity_id === app.volunteer_opportunity_id;
});

// CP1 (0.4): Submitted an application for an open, in-person, children-focused role at a campus in ZIP 30309 within 10 miles
checkpoints.push({ passed: appsWithQualifyingOpportunity.length >= 1, weight: 0.4 });

// CP2 (0.6): That application selects a specific Sunday morning (8am–12pm) service time slot
checkpoints.push({ passed: appsWithSundayMorningSlot.length >= 1, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lessonPlans = JSON.parse(localStorage.getItem('lesson_plans') || '[]');
const seriesList = JSON.parse(localStorage.getItem('lesson_series') || '[]');
const assignments = JSON.parse(localStorage.getItem('series_lesson_assignments') || '[]');

// Series targeting April 2025 and ages 5–7
const candidateSeries = seriesList.filter(s => {
  if (s.month !== 4 || s.year !== 2025) return false;
  const min = typeof s.target_min_age === 'number' ? s.target_min_age : 0;
  const max = typeof s.target_max_age === 'number' ? s.target_max_age : Infinity;
  if (min > 7 || max < 5) return false; // overlap with ages 5–7
  return true;
});

const targetSeries = candidateSeries.length ? candidateSeries[0] : null;

let parableAssignments = [];
if (targetSeries) {
  const seriesAssignments = assignments.filter(a => a.lesson_series_id === targetSeries.id);
  parableAssignments = seriesAssignments.filter(a => {
    const lp = lessonPlans.find(l => l.id === a.lesson_plan_id);
    if (!lp) return false;
    if (lp.topic_category !== 'teachings_of_jesus') return false;
    if (lp.topic_subcategory !== 'parables') return false;
    const min = typeof lp.min_age === 'number' ? lp.min_age : 0;
    const max = typeof lp.max_age === 'number' ? lp.max_age : Infinity;
    if (min > 7 || max < 5) return false;
    return true;
  });
}

const distinctLessonIds = Array.from(new Set(parableAssignments.map(a => a.lesson_plan_id)));

// CP1 (0.3): Created a lesson series for April 2025 that targets ages 5–7
checkpoints.push({ passed: !!targetSeries, weight: 0.3 });

// CP2 (0.3): Series includes four different parable-based lesson plans about Jesus appropriate for ages 5–7
checkpoints.push({ passed: distinctLessonIds.length >= 4, weight: 0.3 });

// CP3 (0.4): Those parable lessons are arranged across weeks 1–4 of the series
let hasWeeks1to4 = false;
if (distinctLessonIds.length >= 4) {
  const weeksUsed = new Set(
    parableAssignments
      .filter(a => distinctLessonIds.includes(a.lesson_plan_id))
      .map(a => a.week_number)
      .filter(w => typeof w === 'number')
  );
  hasWeeks1to4 = [1, 2, 3, 4].every(w => weeksUsed.has(w));
}
checkpoints.push({ passed: hasWeeks1to4, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');
const agesTable = JSON.parse(localStorage.getItem('newsletter_child_ages') || '[]');
const topicsTable = JSON.parse(localStorage.getItem('newsletter_topic_preferences') || '[]');

const candidateSubs = subs.filter(s => {
  if (!s.email) return false;
  if (s.email_frequency !== 'weekly') return false;
  if (s.communication_preference !== 'email_only') return false;
  if (s.send_age_specific_ideas !== true) return false;
  return true;
});

function hasAges(subId, agesNeeded) {
  const ages = agesTable.filter(a => a.newsletter_subscription_id === subId).map(a => a.child_age);
  return agesNeeded.every(age => ages.includes(age));
}

function hasTopics(subId, topicsNeeded) {
  const topics = topicsTable.filter(t => t.newsletter_subscription_id === subId).map(t => t.topic);
  return topicsNeeded.every(t => topics.includes(t));
}

const subsWithAges = candidateSubs.filter(s => hasAges(s.id, [8, 9, 10]));
const subsWithAgesAndTopics = subsWithAges.filter(s => hasTopics(s.id, ['family_devotions', 'helping_kids_pray']));

// CP1 (0.4): Created a weekly newsletter subscription with email-only communication and age-specific ideas enabled
checkpoints.push({ passed: candidateSubs.length >= 1, weight: 0.4 });

// CP2 (0.3): Subscription specifies children ages 8, 9, and 10
checkpoints.push({ passed: subsWithAges.length >= 1, weight: 0.3 });

// CP3 (0.3): Subscription selects both “family devotions” and “helping kids pray” topics
checkpoints.push({ passed: subsWithAgesAndTopics.length >= 1, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const children = JSON.parse(localStorage.getItem('child_profiles') || '[]');
const interestTags = JSON.parse(localStorage.getItem('child_interest_tags') || '[]');
const sponsorships = JSON.parse(localStorage.getItem('sponsorships') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let baseDate = baselineDateStr ? new Date(baselineDateStr) : new Date();
const year = baseDate.getUTCFullYear();
const month = baseDate.getUTCMonth(); // 0-based
const nextMonthDate = new Date(Date.UTC(month === 11 ? year + 1 : year, (month + 1) % 12, 1));
const nextMonthStr = nextMonthDate.toISOString().slice(0, 10);

// Children aged 6–9 who enjoy reading and Bible stories
const candidateChildren = children.filter(c => {
  if (typeof c.age !== 'number' || c.age < 6 || c.age > 9) return false;
  const tags = interestTags.filter(t => t.child_profile_id === c.id).map(t => t.interest);
  return tags.includes('reading_and_bible_stories');
});

// Longest-waiting among those children (earliest date_listed)
let longestWaitingChild = null;
if (candidateChildren.length) {
  longestWaitingChild = candidateChildren.slice().sort((a, b) => {
    const da = a.date_listed ? new Date(a.date_listed) : new Date(0);
    const db = b.date_listed ? new Date(b.date_listed) : new Date(0);
    return da - db;
  })[0];
}

// Sponsorships with correct amount range, method, and start date
const candidateSponsorships = sponsorships.filter(s => {
  if (s.frequency !== 'monthly') return false;
  if (s.payment_method !== 'bill_me_by_mail') return false;
  if (typeof s.monthly_amount !== 'number' || s.monthly_amount < 30 || s.monthly_amount > 40) return false;
  if (!s.start_date) return false;
  const dStr = s.start_date.slice(0, 10);
  if (dStr !== nextMonthStr) return false;
  return true;
});

// CP1 (0.4): Created a monthly sponsorship with a $30–$40 pledge using bill-by-mail, starting on the first day of next month
checkpoints.push({ passed: candidateSponsorships.length >= 1, weight: 0.4 });

// CP2 (0.6): That sponsorship is for the longest-waiting qualifying child (age 6–9, enjoys reading and Bible stories)
let sponsorsLongestWaiting = false;
if (longestWaitingChild) {
  sponsorsLongestWaiting = candidateSponsorships.some(s => s.child_profile_id === longestWaitingChild.id);
}
checkpoints.push({ passed: sponsorsLongestWaiting, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
